/**
 * 生成插件注入的 CSS
 * 设计原则：克制、优雅，不抢视觉焦点，但让结构一目了然
 */
export declare const ENLEARN_STYLES = "\n/* \u5206\u5757\u5BB9\u5668 \u2014 \u4E0D\u7528 position:relative\uFF0C\u907F\u514D\u6321\u4F4F Reddit \u7B49\u7AD9\u70B9\u7684\u8986\u76D6\u5BFC\u822A\u94FE\u63A5 */\n.enlearn-chunked {\n  display: block !important;\n  font-family: inherit;\n  font-size: inherit;\n  line-height: 1.5;\n  padding: 0;\n  margin: 1px 0;\n  background: transparent;\n  border-radius: 0;\n  transition: background 0.2s;\n}\n\n.enlearn-chunked:hover {\n  background: rgba(37, 99, 235, 0.03);\n}\n\n/* \u6BB5\u843D\u95F4\u8DDD */\n.enlearn-para-break { display: block !important; height: 0.8em; }\n\n/* \u7F29\u8FDB\u5C42\u7EA7 */\n.enlearn-line { display: block !important; }\n.enlearn-indent-0 { padding-left: 0; }\n.enlearn-indent-1 { padding-left: 1.0em; }\n.enlearn-indent-2 { padding-left: 2.0em; }\n.enlearn-indent-3 { padding-left: 3.0em; }\n.enlearn-indent-4 { padding-left: 4.0em; }\n.enlearn-indent-5 { padding-left: 5.0em; }\n\n/* \u989C\u8272\u5C42\u7EA7 \u2014 \u4E3B\u53E5\u6B63\u5E38\u8272\uFF0C\u4ECE\u53E5\u9010\u7EA7\u53D8\u6DE1 */\n.enlearn-depth-0 { opacity: 1; }\n.enlearn-depth-1 { opacity: 0.75; }\n.enlearn-depth-2 { opacity: 0.55; }\n.enlearn-depth-3 { opacity: 0.45; }\n.enlearn-depth-4 { opacity: 0.38; }\n.enlearn-depth-5 { opacity: 0.32; }\n\n/* L2/L1\uFF1Ainline \u6A21\u5F0F\u5BB9\u5668 */\n.enlearn-chunked-inline .enlearn-inline-content {\n  display: inline;\n}\n\n/* L2\uFF1A\u884C\u5185\u5206\u9694\u7B26 */\n.enlearn-separator {\n  margin: 0 0.3em;\n  color: rgba(37, 99, 235, 0.35);\n  user-select: none;\n  font-weight: 400;\n}\n\n/* L1\uFF1A\u4ECE\u53E5\u53D8\u6DE1 */\n.enlearn-dim {\n  opacity: 0.5;\n}\n\n/* \u751F\u8BCD\u8F7B\u6807\u8BB0 */\n.enlearn-word {\n  border-bottom: 1px dotted rgba(37, 99, 235, 0.45);\n  cursor: pointer;\n  transition: border-color 0.15s;\n}\n\n.enlearn-word:hover {\n  border-bottom-color: #2563eb;\n}\n\n/* \u5168\u5C40\u6D6E\u7A97 \u2014 position:fixed \u6302\u5728 body\uFF0C\u6C38\u8FDC\u4E0D\u88AB\u5BB9\u5668\u88C1\u526A */\n.enlearn-tooltip {\n  position: fixed;\n  display: none;\n  background: #1a1a2e;\n  color: #e2e8f0;\n  padding: 6px 10px;\n  border-radius: 8px;\n  font-size: 13px;\n  line-height: 1.5;\n  white-space: nowrap;\n  z-index: 2147483647;\n  pointer-events: auto;\n  box-shadow: 0 4px 16px rgba(0,0,0,0.25);\n  font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, sans-serif;\n  display: none;\n  align-items: center;\n  gap: 8px;\n}\n\n.enlearn-tooltip-def {\n  display: inline;\n}\n\n.enlearn-tooltip-btn {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  width: 20px;\n  height: 20px;\n  padding: 0;\n  margin-left: 2px;\n  background: transparent;\n  border: 1.5px solid rgba(255,255,255,0.12);\n  border-radius: 50%;\n  color: rgba(255,255,255,0.25);\n  font-size: 11px;\n  cursor: pointer;\n  transition: all 0.2s;\n  font-family: inherit;\n  line-height: 1;\n  flex-shrink: 0;\n}\n\n.enlearn-tooltip-btn:hover {\n  background: rgba(34,197,94,0.15);\n  border-color: rgba(34,197,94,0.5);\n  color: #4ade80;\n}\n\n/* \u624B\u52A8\u89E6\u53D1\u6309\u94AE \u2014 inline \u663E\u793A\uFF0C\u4E0D\u4F1A\u88AB overflow:hidden \u88C1\u526A */\n.enlearn-trigger {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  vertical-align: middle;\n  width: 18px;\n  height: 18px;\n  margin-left: 6px;\n  border-radius: 4px;\n  background: transparent;\n  border: none;\n  color: rgba(37, 99, 235, 0.35);\n  cursor: pointer;\n  opacity: 0.2;\n  transition: all 0.2s;\n  user-select: none;\n  padding: 0;\n  line-height: 1;\n  pointer-events: auto !important;\n}\n\n.enlearn-trigger svg {\n  width: 14px;\n  height: 14px;\n}\n\n.enlearn-trigger.enlearn-trigger-visible {\n  opacity: 0.6;\n}\n\n.enlearn-trigger:hover {\n  opacity: 1 !important;\n  background: rgba(37, 99, 235, 0.08);\n  color: #2563eb;\n}\n\n.enlearn-trigger.enlearn-trigger-loading {\n  opacity: 1;\n  pointer-events: none;\n  animation: enlearn-pulse 1s ease-in-out infinite;\n}\n\n@keyframes enlearn-pulse {\n  0%, 100% { opacity: 0.4; }\n  50% { opacity: 1; }\n}\n\n/* \u52A0\u8F7D\u4E2D\u72B6\u6001 \u2014 shimmer \u6548\u679C */\n.enlearn-loading {\n  position: relative;\n  overflow: hidden;\n}\n\n.enlearn-loading::after {\n  content: \"\";\n  position: absolute;\n  inset: 0;\n  background: linear-gradient(\n    90deg,\n    transparent 0%,\n    rgba(37, 99, 235, 0.06) 50%,\n    transparent 100%\n  );\n  animation: enlearn-shimmer 1.5s ease-in-out infinite;\n}\n\n@keyframes enlearn-shimmer {\n  0% { transform: translateX(-100%); }\n  100% { transform: translateX(100%); }\n}\n\n/* \u9690\u85CF\u539F\u59CB\u5143\u7D20\uFF08\u5144\u5F1F\u63D2\u5165\u7B56\u7565\uFF1A\u539F\u59CB\u5143\u7D20\u9690\u85CF\uFF0C\u5206\u5757\u4F5C\u4E3A\u5144\u5F1F\u663E\u793A\uFF09 */\n.enlearn-original-hidden {\n  display: none !important;\n}\n\n/* \u8986\u76D6\u622A\u65AD\u6837\u5F0F\uFF0C\u4F7F\u5206\u5757\u5185\u5BB9\u5B8C\u5168\u53EF\u89C1\uFF08Twitter line-clamp / Reddit -webkit-box \u7B49\uFF09\n   \u6CE8\u610F\uFF1A\u4E0D\u5728 CSS \u4E2D\u8BBE display:block\uFF0C\u53EA\u5728 JS \u4E2D\u5BF9 webkit-box \u5143\u7D20\u8BBE\uFF08\u907F\u514D\u7834\u574F flex \u5E03\u5C40\uFF09 */\n.enlearn-clamp-override {\n  -webkit-line-clamp: unset !important;\n  -webkit-box-orient: unset !important;\n  max-height: none !important;\n  overflow: visible !important;\n  text-overflow: unset !important;\n}\n\n/* \u6682\u505C\u72B6\u6001 \u2014 \u663E\u793A\u539F\u6587\u3001\u9690\u85CF\u5206\u5757 */\nbody.enlearn-paused .enlearn-chunked { display: none !important; }\nbody.enlearn-paused .enlearn-trigger { display: none !important; }\nbody.enlearn-paused .enlearn-original-hidden { display: block !important; }\n\n/* \u6697\u8272\u6A21\u5F0F\u9002\u914D */\n@media (prefers-color-scheme: dark) {\n  .enlearn-chunked:hover {\n    background: rgba(96, 165, 250, 0.05);\n  }\n\n  .enlearn-word {\n    border-bottom-color: rgba(96, 165, 250, 0.45);\n  }\n\n  .enlearn-word:hover {\n    border-bottom-color: #60a5fa;\n  }\n\n  .enlearn-tooltip {\n    background: #0f0f1a;\n    color: #e2e8f0;\n    box-shadow: 0 4px 20px rgba(0,0,0,0.4);\n  }\n\n  .enlearn-tooltip-btn {\n    border-color: rgba(255,255,255,0.1);\n    color: rgba(255,255,255,0.2);\n  }\n\n  .enlearn-trigger {\n    color: rgba(96, 165, 250, 0.35);\n  }\n\n  .enlearn-trigger:hover {\n    opacity: 1 !important;\n    background: rgba(96, 165, 250, 0.12);\n    color: #60a5fa;\n  }\n\n  .enlearn-separator {\n    color: rgba(96, 165, 250, 0.35);\n  }\n\n  .enlearn-loading::after {\n    background: linear-gradient(\n      90deg,\n      transparent 0%,\n      rgba(96, 165, 250, 0.08) 50%,\n      transparent 100%\n    );\n  }\n\n}\n";
